import android.nfc.NfcAdapter;
import android.nfc.Tag;
import android.nfc.tech.IsoDep;
import java.nio.ByteBuffer;
import java.security.SecureRandom;

/**
 * Distance Bounding Protocol Implementation for NFC Payment Security
 * Based on Brands-Chaum protocol with modifications for EMV compatibility
 */
public class NFCDistanceBoundingValidator {

    // Constants
    private static final int MAX_ALLOWED_RTT_MS = 3; // Maximum round-trip time in milliseconds
    private static final int CHALLENGE_SIZE = 16; // 128-bit challenge
    private static final int NUM_RAPID_EXCHANGES = 8; // Number of rapid bit exchanges
    private static final double SPEED_OF_LIGHT = 299792458.0; // meters per second
    private static final double MAX_PROXIMITY_METERS = 0.45; // ~3ms at speed of light

    private final SecureRandom secureRandom;
    private final IsoDep nfcTag;

    public NFCDistanceBoundingValidator(Tag tag) throws Exception {
        this.secureRandom = new SecureRandom();
        this.nfcTag = IsoDep.get(tag);

        if (nfcTag == null) {
            throw new IllegalArgumentException("Tag does not support ISO-DEP (ISO 14443-4)");
        }

        // Set timeout to strict value for distance bounding
        nfcTag.setTimeout(100); // 100ms total timeout
    }

    /**
     * Performs distance bounding verification before allowing transaction
     * @return true if device is within acceptable proximity (not relayed)
     * @throws Exception if communication fails
     */
    public boolean verifyProximity() throws Exception {
        // Phase 1: Initialize distance bounding session
        byte[] sessionNonce = initializeDistanceBounding();

        // Phase 2: Rapid bit exchange (time-critical)
        long[] roundTripTimes = performRapidBitExchange();

        // Phase 3: Verify responses and analyze timing
        boolean isProximate = analyzeTimingResults(roundTripTimes);

        if (!isProximate) {
            logSecurityEvent("RELAY_ATTACK_SUSPECTED", roundTripTimes);
            return false;
        }

        return true;
    }

    /**
     * Initialize distance bounding protocol with challenge-response setup
     */
    private byte[] initializeDistanceBounding() throws Exception {
        // Generate cryptographic nonce
        byte[] nonce = new byte[CHALLENGE_SIZE];
        secureRandom.nextBytes(nonce);

        // Send initialization command (custom APDU)
        byte[] initCommand = buildAPDU((byte)0x00, (byte)0xDB, (byte)0x01, (byte)0x00, nonce);

        if (!nfcTag.isConnected()) {
            nfcTag.connect();
        }

        byte[] response = nfcTag.transceive(initCommand);

        // Verify initialization response
        if (response.length < 2 || response[response.length - 2] != (byte)0x90) {
            throw new SecurityException("Distance bounding initialization failed");
        }

        return nonce;
    }

    /**
     * Perform rapid challenge-response bit exchanges to measure round-trip time
     */
    private long[] performRapidBitExchange() throws Exception {
        long[] roundTripTimes = new long[NUM_RAPID_EXCHANGES];

        for (int i = 0; i < NUM_RAPID_EXCHANGES; i++) {
            // Generate random challenge bit
            byte challengeBit = (byte)(secureRandom.nextInt(2));

            // Create minimal APDU for single-bit challenge (optimized for speed)
            byte[] rapidCommand = new byte[] {
                (byte)0x00, (byte)0xDB, (byte)0x02, challengeBit, (byte)0x01
            };

            // Measure round-trip time with nanosecond precision
            long startTime = System.nanoTime();
            byte[] response = nfcTag.transceive(rapidCommand);
            long endTime = System.nanoTime();

            roundTripTimes[i] = (endTime - startTime) / 1_000_000; // Convert to milliseconds

            // Verify response bit (should be function of challenge)
            if (response.length == 0 || !isValidResponseBit(challengeBit, response[0])) {
                throw new SecurityException("Invalid distance bounding response at iteration " + i);
            }
        }

        return roundTripTimes;
    }

    /**
     * Analyze timing results to detect relay attacks
     */
    private boolean analyzeTimingResults(long[] roundTripTimes) {
        // Calculate statistics
        double avgRTT = calculateAverage(roundTripTimes);
        double maxRTT = calculateMax(roundTripTimes);
        double stdDev = calculateStdDev(roundTripTimes, avgRTT);

        // Criteria for legitimate proximity:
        // 1. Average RTT must be under threshold
        // 2. Maximum single RTT must be under threshold
        // 3. Standard deviation should be low (relay attacks have variable latency)

        boolean avgWithinLimit = avgRTT <= MAX_ALLOWED_RTT_MS;
        boolean maxWithinLimit = maxRTT <= MAX_ALLOWED_RTT_MS * 1.5;
        boolean consistentTiming = stdDev <= 1.0; // Low jitter expected for genuine NFC

        return avgWithinLimit && maxWithinLimit && consistentTiming;
    }

    /**
     * Validate response bit using cryptographic commitment
     */
    private boolean isValidResponseBit(byte challenge, byte response) {
        // Simple XOR function for demonstration
        // In production, use HMAC or other cryptographic function
        return (response & 0x01) == ((challenge ^ 0x01) & 0x01);
    }

    /**
     * Build ISO 7816-4 APDU command
     */
    private byte[] buildAPDU(byte cla, byte ins, byte p1, byte p2, byte[] data) {
        ByteBuffer buffer = ByteBuffer.allocate(5 + (data != null ? data.length : 0));
        buffer.put(cla);
        buffer.put(ins);
        buffer.put(p1);
        buffer.put(p2);
        buffer.put((byte)(data != null ? data.length : 0));
        if (data != null) {
            buffer.put(data);
        }
        return buffer.array();
    }

    // Statistical helper methods
    private double calculateAverage(long[] values) {
        long sum = 0;
        for (long v : values) sum += v;
        return (double)sum / values.length;
    }

    private double calculateMax(long[] values) {
        long max = values[0];
        for (long v : values) if (v > max) max = v;
        return max;
    }

    private double calculateStdDev(long[] values, double mean) {
        double sumSquaredDiff = 0;
        for (long v : values) {
            double diff = v - mean;
            sumSquaredDiff += diff * diff;
        }
        return Math.sqrt(sumSquaredDiff / values.length);
    }

    /**
     * Log security event for SIEM analysis
     */
    private void logSecurityEvent(String eventType, long[] timings) {
        // Send to security monitoring system
        String logMessage = String.format(
            "{\"event\":\"%s\", \"avg_rtt_ms\":%.2f, \"max_rtt_ms\":%.2f, \"timestamp\":\"%s\"}",
            eventType,
            calculateAverage(timings),
            calculateMax(timings),
            java.time.Instant.now().toString()
        );

        android.util.Log.w("NFCSecurity", logMessage);
        // TODO: Send to centralized logging (Splunk, Azure Sentinel, etc.)
    }

    /**
     * Main integration point for payment flow
     */
    public boolean authorizePayment(Tag nfcTag, double amount) throws Exception {
        // Step 1: Verify proximity using distance bounding
        if (!verifyProximity()) {
            throw new SecurityException("Payment rejected: Relay attack suspected (distance verification failed)");
        }

        // Step 2: Proceed with standard EMV contactless transaction
        // ... (existing EMV flow)

        return true;
    }
}

/**
 * Usage in payment activity:
 * 
 * @Override
 * protected void onNewIntent(Intent intent) {
 *     Tag tag = intent.getParcelableExtra(NfcAdapter.EXTRA_TAG);
 *     
 *     try {
 *         NFCDistanceBoundingValidator validator = new NFCDistanceBoundingValidator(tag);
 *         
 *         if (validator.authorizePayment(tag, transactionAmount)) {
 *             processPayment();
 *         }
 *     } catch (SecurityException e) {
