event.category: "payment" AND payment.type: "contactless"
| runtime_field distance_km {
    type: double
    script: """
      if (doc['merchant.location'].size() > 0 && doc['merchant.previous_location'].size() > 0) {
        emit(doc['merchant.location'].arcDistance(doc['merchant.previous_location']) / 1000);
      }
    """
  }
| runtime_field velocity_kmh {
    type: double
    script: """
      if (doc['@timestamp'].size() > 0 && doc['payment.previous_timestamp'].size() > 0) {
        double time_diff_hours = (doc['@timestamp'].value.toEpochMilli() - doc['payment.previous_timestamp'].value.toEpochMilli()) / 3600000.0;
        if (time_diff_hours > 0) {
          emit(doc['distance_km'].value / time_diff_hours);
        }
      }
    """
  }
| where velocity_kmh > 200
| sort velocity_kmh desc
